INSERT INTO crop_atlas (crop_name, category, growth_cycle, common_pests, description) VALUES
('水稻', '粮食作物', '约120至150天', '稻飞虱、稻纵卷叶螟、二化螟、纹枯病、稻瘟病', '水稻飞防作业飞行高度建议距冠层1.5至2.5米，亩喷液量1至1.5升，下压风场可使药液穿透至中下部茎叶。关键防治期为分蘖末期至孕穗破口期，重点防治稻飞虱与稻纵卷叶螟。宜在清晨或傍晚气温低、风速小于3米每秒时作业，避开正午高温与扬花授粉时段，杀虫剂应交替轮换以延缓抗性。'),
('小麦', '粮食作物', '约230天（冬小麦）', '小麦蚜虫、白粉病、赤霉病、条锈病、麦红蜘蛛', '小麦飞防高度宜距冠层1.5至2米，亩喷液量1至1.5升。抽穗扬花期是赤霉病防治关键窗口，需抢在初花期一次施药、雨前抢喷。穗期可一喷三防（杀菌、杀虫、叶面肥）兼治蚜虫与锈病。作业宜选无风或微风晴天上午，避开扬花高峰与降雨前后，添加飞防助剂增强叶面附着。'),
('玉米', '粮食作物', '约90至120天', '玉米螟、草地贪夜蛾、蚜虫、大斑病、粘虫', '玉米中后期植株高大，飞防优势明显，飞行高度距冠层2至3米，亩喷液量1.5至2升。草地贪夜蛾应在低龄幼虫期靶向喷洒喇叭口与心叶部位，于傍晚或清晨幼虫取食活跃时施药效果佳。大喇叭口期是防治玉米螟的关键时期，注意杀虫剂轮换使用以延缓抗药性。'),
('马铃薯', '粮食作物', '约90至120天', '晚疫病、马铃薯甲虫、蚜虫、早疫病、地下害虫', '马铃薯飞防高度距冠层1.5至2米，亩喷液量1.5至2升。晚疫病是毁灭性病害，应在现蕾封垄期预防性施药，遇连阴雨低温高湿天气须缩短间隔抢喷保护性杀菌剂。作业宜在露水干后、无雨晴朗时段进行，保护剂与治疗剂交替使用，确保叶片正反面均匀着药。'),
('棉花', '经济作物', '约150天', '棉铃虫、棉蚜、棉叶螨、烟粉虱、盲蝽', '棉花飞防高度距冠层1.5至2.5米，亩喷液量1至1.5升。蕾铃期是棉铃虫防治关键，应在卵孵盛期至低龄幼虫期用药。后期可结合脱叶催熟剂飞防，需保证雾滴均匀覆盖中下部。宜在清晨或傍晚作业，高温干旱时棉叶螨易暴发，应及时挑治并轮换杀螨剂以防抗性。'),
('油菜', '经济作物', '约200天（冬油菜）', '菌核病、蚜虫、霜霉病、跳甲、潜叶蝇', '油菜飞防高度距冠层1.5至2米，亩喷液量1至1.5升。菌核病防治关键期为盛花期，应在主茎开花株率达80%时施药，重点喷布中下部茎秆与老叶。蕾薹至初花期兼治蚜虫。作业避开蜜蜂采蜜高峰时段以保护授粉昆虫，宜选无风晴天，花期施药尤需注意减少药害与对传粉昆虫影响。'),
('花生', '经济作物', '约120至150天', '花生叶斑病、蚜虫、棉铃虫、蛴螬、锈病', '花生飞防高度距冠层1.5至2米，亩喷液量1至1.5升。叶斑病（褐斑病与黑斑病）在结荚期高温高湿易流行，应于发病初期施保护性杀菌剂并隔7至10天连喷。地下蛴螬危害严重，飞防难以触及，需配合根部撒施颗粒剂。宜清晨露水干后或傍晚作业，添加助剂提高雾滴附着。'),
('大豆', '经济作物', '约100至130天', '大豆食心虫、蚜虫、豆荚螟、霜霉病、点蜂缘蝽', '大豆飞防高度距冠层1.5至2米，亩喷液量1至1.5升。食心虫应在成虫羽化盛期至产卵初期施药，鼓粒期前防治效果最佳。蚜虫与点蜂缘蝽在结荚期需重点监测。作业宜在傍晚成虫活动期进行，避开正午高温与花期，杀虫剂注意轮换，添加飞防专用助剂增强渗透与抗蒸发。'),
('甘蔗', '经济作物', '多年生（宿根）', '甘蔗螟虫、蓟马、绵蚜、凤梨病、黑穗病', '甘蔗植株高大，飞防作业优势突出，飞行高度距冠层2.5至3.5米，亩喷液量2至3升。螟虫应在卵孵盛期施药，分蘖至伸长期是防治关键，可结合赤眼蜂生物防治。蓟马在苗期心叶危害重，需靶向喷洒。宜在清晨或傍晚作业，注意叶片密集需加大喷液量保证穿透与覆盖。'),
('柑橘', '果树', '多年生', '柑橘红蜘蛛、潜叶蛾、蚧壳虫、炭疽病、溃疡病', '柑橘飞防采用低速低高度果树喷洒，飞行高度距树冠1至2米，亩喷液量3至5升以保证茂密树冠的内膛着药。红蜘蛛春梢期与秋季易暴发，应挑治并轮换杀螨剂。新梢抽发期防潜叶蛾。溃疡病在台风暴雨后及新梢期喷铜制剂保护。宜无风时段作业，避开高温与开花期以保护蜜蜂。'),
('苹果', '果树', '多年生', '苹果红蜘蛛、桃小食心虫、蚜虫、轮纹病、斑点落叶病', '苹果飞防低速低高度果树喷洒，距树冠1至2米，亩喷液量3至5升。花后至套袋前是病虫害防治关键期，重点防斑点落叶病与红蜘蛛。桃小食心虫应在卵果率达1%时施药。谢花后开始全程保护性杀菌防轮病。宜选无风晴天，避开盛花期施药以保护授粉，雨季前后注意抢喷保护剂。'),
('葡萄', '果树', '多年生', '霜霉病、白粉病、灰霉病、葡萄透翅蛾、绿盲蝽', '葡萄飞防距冠层1至2米，亩喷液量3至4升，需保证叶片背面着药。霜霉病在多雨高湿季节流行迅速，应于发病前预防性施保护剂，发病后改用内吸治疗剂并缩短间隔。花前花后是绿盲蝽与灰霉病防治关键。宜无风晴朗时段作业，避开花期，杀菌剂多作用机理交替使用以防抗性。'),
('香蕉', '果树', '约300至365天', '香蕉叶斑病、香蕉象甲、蓟马、束顶病、炭疽病', '香蕉植株高大叶片宽阔，飞防优势显著，飞行高度距冠层2.5至3.5米，亩喷液量3至5升。叶斑病（黑星病与黄条叶斑病）在高温高湿雨季流行，需在新叶期预防性连续施药并轮换药剂。蓟马危害幼果影响果面。宜清晨或傍晚无风时作业，确保心叶与叶背均匀着药，雨季缩短施药间隔。'),
('芒果', '果树', '多年生', '芒果炭疽病、横线尾夜蛾、蓟马、白粉病、果实蝇', '芒果飞防低速低高度果树喷洒，距树冠1.5至2.5米，亩喷液量3至5升。炭疽病在花期与幼果期高湿条件下高发，应于花序抽生期至坐果期保护性连喷。白粉病在花期威胁坐果。果实蝇需结合诱杀。宜在无风清晨作业，花期施药须慎选低毒药剂并避开蜜蜂活动高峰，确保花序均匀着药。'),
('番茄', '蔬菜', '约90至120天', '番茄晚疫病、烟粉虱、棉铃虫、灰霉病、病毒病', '番茄飞防高度距冠层1至1.5米，亩喷液量1.5至2升。晚疫病在低温高湿连阴雨时暴发迅速，应预防为主、发病初期抢喷保护与治疗复配剂。烟粉虱传播病毒病，需早期防控并轮换药剂。灰霉病在棚室高湿易发。宜露水干后无风时作业，注意叶背与果面着药，设施内作业兼顾通风降湿。'),
('辣椒', '蔬菜', '约100至130天', '辣椒疫病、蚜虫、烟粉虱、炭疽病、蓟马', '辣椒飞防高度距冠层1至1.5米，亩喷液量1.5至2升。疫病为高温高湿期毁灭性病害，雨后及时施保护剂并配合排水降湿。蚜虫与烟粉虱传播病毒病，应苗期早防。炭疽病在果实成熟期易发，需于发病初期连喷。宜清晨或傍晚作业避开高温，杀菌剂保护剂与内吸剂交替使用以延缓抗性发展。'),
('茶叶', '其他', '多年生', '茶小绿叶蝉、茶尺蠖、茶毛虫、茶橙瘿螨、茶炭疽病', '茶叶飞防距蓬面0.5至1.5米，亩喷液量2至3升，需保证蓬面与叶背均匀着药。茶小绿叶蝉是首要害虫，应在若虫高峰期施药，优先选用低毒低残留生物农药。采摘期须严格遵守安全间隔期保障茶叶质量安全。宜清晨露水干后无风时作业，避开采摘前，杀虫剂轮换使用，严禁使用禁限用农药。'),
('烟草', '其他', '约120天', '烟青虫、烟蚜、烟草赤星病、青枯病、花叶病', '烟草飞防高度距冠层1.5至2米，亩喷液量1.5至2升。赤星病在成熟采收期高温高湿条件下流行，应于下部叶片发病初期施药并自下而上保护。烟蚜传播花叶病毒病，需团棵期早防并轮换药剂。烟青虫在打顶后蛀食心叶，应及时挑治。宜清晨或傍晚作业，采收期严格执行安全间隔期，确保烟叶品质与残留合格。');
INSERT INTO pesticide_ratio (pesticide_name, crop_name, pest_name, dosage, water_ratio, spray_method, safety_interval, notes) VALUES
('25%吡蚜酮悬浮剂', '水稻', '稻飞虱', '20至30克每亩', '亩喷液量1至1.5升，需先二次稀释', '低空均匀喷洒', '14天', '于若虫高峰期施药，与噻虫嗪等不同机理药剂轮换使用以延缓抗性，避开正午高温与扬花期，添加飞防助剂增强穿透。'),
('5%甲氨基阿维菌素苯甲酸盐水分散粒剂', '水稻', '稻纵卷叶螟', '8至10克每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '14天', '在低龄幼虫卷叶前施药效果最佳，宜傍晚作业避免光解，与氯虫苯甲酰胺等轮换使用，二次稀释充分混匀。'),
('20%三环唑可湿性粉剂', '水稻', '稻瘟病', '75至100克每亩', '亩喷液量1.5升', '低空均匀喷洒', '21天', '于破口前5至7天预防性施药保护穗颈，叶瘟发病初期补喷，宜无风时段作业，雨前抢喷提高保护效果。'),
('井冈霉素A', '水稻', '纹枯病', '10至15克每亩（折纯）', '亩喷液量1.5升', '低空均匀喷洒，加大下部着药', '14天', '分蘖末期至孕穗期病株率达标时施药，重点喷布植株中下部，高温高湿期可缩短间隔连喷，注意药液穿透。'),
('10%吡虫啉可湿性粉剂', '小麦', '小麦蚜虫', '20至30克每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '14天', '穗期蚜量达标时施药，可结合一喷三防，与抗蚜威或啶虫脒轮换，避开扬花高峰，添加助剂提高附着。'),
('430克每升戊唑醇悬浮剂', '小麦', '赤霉病', '15至20毫升每亩', '亩喷液量1.5升', '低空均匀喷洒', '28天', '抢在小麦初花期首次施药、间隔7天再喷，雨前抢喷穗部，与氰烯菌酯等复配轮换以兼顾抗性与降毒素。'),
('25%三唑酮可湿性粉剂', '小麦', '白粉病', '30至40克每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '20天', '发病初期施药，重点喷布中下部叶片，与氟环唑等不同机理杀菌剂轮换，避开高温强光时段以防药害。'),
('200克每升氯虫苯甲酰胺悬浮剂', '玉米', '草地贪夜蛾', '10至15毫升每亩', '亩喷液量1.5至2升', '靶向喷洒喇叭口与心叶', '21天', '抓住低龄幼虫期傍晚施药，靶向喇叭口与心叶，与乙基多杀菌素轮换，二次稀释，避免与碱性农药混用。'),
('苏云金杆菌Bt', '玉米', '玉米螟', '100至150克每亩', '亩喷液量1.5至2升', '靶向喷洒喇叭口', '采收期可用', '大喇叭口期低龄幼虫期施用，宜傍晚或阴天作业避免紫外失活，不可与杀菌剂及碱性药剂混用，现配现用。'),
('250克每升嘧菌酯悬浮剂', '马铃薯', '晚疫病', '40至60毫升每亩', '亩喷液量1.5至2升', '低空均匀喷洒', '14天', '现蕾封垄期预防性施药，连阴雨高湿期缩短间隔，与代森锰锌等保护剂交替，确保叶背着药，雨前抢喷。'),
('80%代森锰锌可湿性粉剂', '马铃薯', '早疫病', '120至150克每亩', '亩喷液量1.5至2升', '低空均匀喷洒', '14天', '发病前作保护性施药，与内吸治疗剂交替使用，均匀覆盖叶片正反面，高温时段避免施药以防药害。'),
('5%甲氨基阿维菌素苯甲酸盐水分散粒剂', '棉花', '棉铃虫', '10至15克每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '14天', '卵孵盛期至低龄幼虫期施药，重点喷蕾铃部位，与茚虫威等轮换，傍晚作业减少光解，二次稀释充分。'),
('22%螺虫乙酯悬浮剂', '棉花', '棉蚜', '15至20毫升每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '21天', '蚜虫发生初期施药，内吸传导性好，与吡虫啉等轮换延缓抗性，避开高温干旱正午，添加助剂增效。'),
('43%联苯肼酯悬浮剂', '棉花', '棉叶螨', '15至20毫升每亩', '亩喷液量1.5升', '低空均匀喷洒，注意叶背', '21天', '螨点零星时挑治，重点喷叶背，与乙螨唑等不同机理杀螨剂轮换，高温干旱期及时防控防止扩散蔓延。'),
('40%菌核净可湿性粉剂', '油菜', '菌核病', '100至150克每亩', '亩喷液量1至1.5升', '低空均匀喷洒中下部', '28天', '盛花期主茎开花株率达80%时施药，重点喷中下部茎秆与老叶，避开蜜蜂采蜜高峰，必要时隔7天再喷一次。'),
('3%啶虫脒乳油', '油菜', '蚜虫', '30至40毫升每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '14天', '蕾薹至初花期蚜量达标时施药，避开蜜蜂活动时段以保护授粉昆虫，与吡虫啉轮换使用，添加飞防助剂。'),
('250克每升丙环唑乳油', '花生', '叶斑病', '30至40毫升每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '21天', '结荚期发病初期施药，隔7至10天连喷2至3次，与苯醚甲环唑等轮换，均匀着药，避开高温强光时段。'),
('70%吡虫啉水分散粒剂', '花生', '蚜虫', '4至6克每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '14天', '苗期至开花期蚜虫发生初期施药，内吸性强，与啶虫脒轮换防抗性，二次稀释，避开正午高温作业。'),
('20%氯虫苯甲酰胺悬浮剂', '大豆', '食心虫', '8至10毫升每亩', '亩喷液量1至1.5升', '低空均匀喷洒', '14天', '成虫羽化盛期至产卵初期施药，鼓粒前防治最佳，傍晚作业，与甲维盐轮换，避免与强碱性农药混用。'),
